mapper.select:
SELECT s.* FROM student s JOIN ( SELECT DISTINCT s.id FROM student s JOIN course_record cr ON s.id = cr.student_id JOIN teacher_course tc ON cr.course_id = tc.course_id LEFT JOIN parent_student ps ON s.id = ps.student_id LEFT JOIN parent p ON ps.parent_id = p.id
tc.teacher_id = #{dto.teacherId}
AND ( s.student_name LIKE CONCAT('%', #{dto.keyword}, '%') OR s.id LIKE CONCAT('%', #{dto.keyword}, '%') OR p.phone LIKE CONCAT('%', #{dto.keyword}, '%') )
) AS temp ON s.id = temp.id
ORDER BY s.create_time DESC, s.id DESC
